policies.inbound:






					{{ExpectedAudience}}








		<set-variable name="requestBody" value="@(context.Request.Body.As(preserveContent: true))" />

		<set-variable name="deploymentId" value="@{
			var path = context.Request.Url.Path;
			var marker = "/deployments/";
			var idx = path.IndexOf(marker, StringComparison.OrdinalIgnoreCase);
			if (idx >= 0) {
				var rest = path.Substring(idx + marker.Length);
				var slash = rest.IndexOf('/');
				if (slash >= 0) { return rest.Substring(0, slash); }
				return rest;
			}
			try {
				var body = context.Variables.GetValueOrDefault("requestBody");
				if (!string.IsNullOrEmpty(body)) {
					var json = Newtonsoft.Json.Linq.JObject.Parse(body);
					var model = json["model"]?.ToString();
					if (!string.IsNullOrEmpty(model)) { return model; }
				}
			} catch { }
			var segments = path.Split('/');
			if (segments.Length > 1) { return segments[segments.Length - 1]; }
			return "unknown";
		}" />


			{{KeycloakTokenEndpoint}}
			POST

				application/x-www-form-urlencoded

			@{
				return "grant_type=client_credentials&client_id={{AIPolicyEngineApimClientId}}&client_secret={{AIPolicyEngineApimClientSecret}}&audience={{ExpectedAudience}}";
			}

		<set-variable name="backend-access-token" value="@{
			var response = ((IResponse)context.Variables["keycloakTokenResponse"]).Body.As();
			return (string)response["access_token"];
		}" />



			@((string)context.Variables["containerAppBaseUrl"] + "/api/precheck/" + (string)context.Variables["clientAppId"] + "/" + (string)context.Variables["tenantId"] + "?deploymentId=" + (string)context.Variables["deploymentId"])
			GET

				@("Bearer " + (string)context.Variables["backend-access-token"])






					application/json
					@{
						var resp = context.Variables["precheckResponse"] as IResponse;
						return resp != null ? resp.Body.As() : "{\"error\":\"Pre-check failed — could not reach authorization service\"}";
					}





					application/json
					@(((IResponse)context.Variables["precheckResponse"]).Body.As())





					application/json
					@(((IResponse)context.Variables["precheckResponse"]).Body.As())





					application/json
					{"error":"Pre-authorization check failed"}




		<set-variable name="routedDeployment"
			value="@(((IResponse)context.Variables["precheckResponse"]).Body.As(preserveContent: true)["routedDeployment"]?.ToString())" />
		<set-variable name="routingPolicyId"
			value="@(((IResponse)context.Variables["precheckResponse"]).Body.As(preserveContent: true)["routingPolicyId"]?.ToString())" />












		@{
            var rawBody = context.Variables.GetValueOrDefault("requestBody");
            var requestBody = Newtonsoft.Json.Linq.JObject.Parse(rawBody);
            if (requestBody["stream"] != null && (bool)requestBody["stream"] == true) {
                requestBody["stream_options"] = Newtonsoft.Json.Linq.JObject.Parse(@"{""include_usage"":true}");
            }
            return requestBody.ToString();
        }
